1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type Scenario = { customer?: Customer; steps: Array<{ op: string; items: Array<Item> }> };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	const CURSED_SURCHARGE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_YEARS_THRESHOLD = 2;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	function withFirstInsuranceSurcharge(basePremium: number): number {
23	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
24	}
25	
26	function surchargeIf(condition: boolean, basePremium: number, rate: number): number {
27	  return condition ? basePremium * rate : 0;
28	}
29	
30	function quoteItem(item: Item): number {
31	  const basePremium = BASE_PREMIUMS[item.type];
32	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
33	  const cursedSurcharge = surchargeIf(item.cursed === true, basePremium, CURSED_SURCHARGE_RATE);
34	  const highEnchantmentSurcharge = surchargeIf(
35	    isHighlyEnchanted,
36	    basePremium,
37	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
38	  );
39	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge + highEnchantmentSurcharge;
40	}
41	
42	const COMPONENT_TYPES = ["rune", "moonstone"];
43	const BLOCK_OF_THREE_BASE = 60;
44	
45	function countByType(items: Array<Item>): Record<string, number> {
46	  const counts: Record<string, number> = {};
47	  for (const item of items) {
48	    counts[item.type] = (counts[item.type] ?? 0) + 1;
49	  }
50	  return counts;
51	}
52	
53	function isLoyalCustomer(customer: Customer | undefined): boolean {
54	  return (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
55	}
56	
57	export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
58	  const { customer, steps } = scenario as Scenario;
59	  const items = steps[0].items;
60	  const counts = countByType(items);
61	
62	  let itemsPremium = 0;
63	  let sumOfBases = 0;
64	  const bundledTypes = new Set<string>();
65	  for (const componentType of COMPONENT_TYPES) {
66	    if (counts[componentType] === 3) {
67	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
68	      sumOfBases += BLOCK_OF_THREE_BASE;
69	      bundledTypes.add(componentType);
70	    }
71	  }
72	
73	  for (const item of items) {
74	    if (bundledTypes.has(item.type)) continue;
75	    itemsPremium += quoteItem(item);
76	    sumOfBases += BASE_PREMIUMS[item.type];
77	  }
78	
79	  if (isLoyalCustomer(customer)) {
80	    itemsPremium -= sumOfBases * LOYALTY_DISCOUNT_RATE;
81	  }
82	
83	  const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
84	  return { results: [{ premium }] };
85	}
